//! Core database tables owned by convergio-db.
//!
//! _schema_registry — managed by migration runner
//! _sync_meta — last sync timestamp per peer+table
//! _sync_conflicts — recorded merge conflicts

use convergio_types::extension::Migration;

/// Core migrations for convergio-db owned tables.
pub fn core_migrations() -> Vec<Migration> {
    vec![Migration {
        version: 1,
        description: "core sync tables",
        up: "\
CREATE TABLE IF NOT EXISTS _sync_meta (
    peer TEXT NOT NULL,
    table_name TEXT NOT NULL,
    last_synced TEXT NOT NULL,
    PRIMARY KEY (peer, table_name)
);
CREATE TABLE IF NOT EXISTS _sync_conflicts (
    id INTEGER PRIMARY KEY AUTOINCREMENT,
    table_name TEXT NOT NULL,
    pk TEXT NOT NULL,
    local_data TEXT,
    remote_data TEXT,
    resolved INTEGER NOT NULL DEFAULT 0,
    created_at TEXT NOT NULL DEFAULT (datetime('now'))
);",
    }]
}

#[cfg(test)]
mod tests {
    use super::*;
    use crate::migration::apply_migrations;
    use rusqlite::Connection;

    #[test]
    fn core_migrations_apply() {
        let conn = Connection::open_in_memory().unwrap();
        let migrations = core_migrations();
        let applied = apply_migrations(&conn, "convergio-db", &migrations).unwrap();
        assert_eq!(applied, 1);

        // Verify tables exist
        let sync_meta: bool = conn
            .query_row(
                "SELECT COUNT(*) > 0 FROM sqlite_master WHERE name = '_sync_meta'",
                [],
                |r| r.get(0),
            )
            .unwrap();
        assert!(sync_meta);
    }
}

//! DbExtension — provides the `db-pool` capability to the depgraph.
//!
//! The database pool is infrastructure, not a service with routes.
//! This extension exists solely to declare the `db-pool` capability
//! so that modules depending on it pass depgraph validation.

use convergio_types::extension::{Extension, Health};
use convergio_types::manifest::{Capability, Manifest, ModuleKind};

/// Minimal extension that declares the `db-pool` capability.
pub struct DbExtension;

impl Extension for DbExtension {
    fn manifest(&self) -> Manifest {
        Manifest {
            id: "convergio-db".into(),
            description: "SQLite connection pool and migration runner".into(),
            version: "1.0.0".into(),
            kind: ModuleKind::Core,
            provides: vec![Capability {
                name: "db-pool".into(),
                version: "1.0.0".into(),
                description: "r2d2 SQLite connection pool".into(),
            }],
            requires: vec![],
            agent_tools: vec![],
            required_roles: vec![],
        }
    }

    fn health(&self) -> Health {
        Health::Ok
    }
}

#[cfg(test)]
mod tests {
    use super::*;

    #[test]
    fn manifest_provides_db_pool() {
        let ext = DbExtension;
        let m = ext.manifest();
        assert_eq!(m.id, "convergio-db");
        assert!(m.provides.iter().any(|c| c.name == "db-pool"));
    }
}

//! Query helpers and schema introspection.

use rusqlite::Connection;

/// Check if a table exists in the database.
pub fn table_exists(conn: &Connection, table: &str) -> rusqlite::Result<bool> {
    conn.query_row(
        "SELECT COUNT(*) > 0 FROM sqlite_master WHERE type='table' AND name=?1",
        [table],
        |r| r.get(0),
    )
}

/// Check if a column exists in a table.
pub fn column_exists(conn: &Connection, table: &str, column: &str) -> rusqlite::Result<bool> {
    let columns = get_column_names(conn, table)?;
    Ok(columns.iter().any(|c| c == column))
}

/// Get all column names for a table.
pub fn get_column_names(conn: &Connection, table: &str) -> rusqlite::Result<Vec<String>> {
    let mut stmt = conn.prepare(&format!("PRAGMA table_info('{table}')"))?;
    let names = stmt
        .query_map([], |row| row.get::<_, String>(1))?
        .filter_map(|r| r.ok())
        .collect();
    Ok(names)
}

/// Check if an index exists.
pub fn index_exists(conn: &Connection, index: &str) -> rusqlite::Result<bool> {
    conn.query_row(
        "SELECT COUNT(*) > 0 FROM sqlite_master WHERE type='index' AND name=?1",
        [index],
        |r| r.get(0),
    )
}

/// Returns true if the error is SQLITE_BUSY or SQLITE_LOCKED.
pub fn is_busy_error(e: &rusqlite::Error) -> bool {
    match e {
        rusqlite::Error::SqliteFailure(err, _) => {
            matches!(
                err.code,
                rusqlite::ffi::ErrorCode::DatabaseBusy | rusqlite::ffi::ErrorCode::DatabaseLocked
            )
        }
        _ => false,
    }
}

#[cfg(test)]
mod tests {
    use super::*;

    fn test_conn() -> Connection {
        let conn = Connection::open_in_memory().unwrap();
        conn.execute_batch("CREATE TABLE example (id INTEGER PRIMARY KEY, name TEXT, age INTEGER)")
            .unwrap();
        conn
    }

    #[test]
    fn table_exists_true() {
        let conn = test_conn();
        assert!(table_exists(&conn, "example").unwrap());
    }

    #[test]
    fn table_exists_false() {
        let conn = test_conn();
        assert!(!table_exists(&conn, "nonexistent").unwrap());
    }

    #[test]
    fn column_exists_true() {
        let conn = test_conn();
        assert!(column_exists(&conn, "example", "name").unwrap());
    }

    #[test]
    fn column_exists_false() {
        let conn = test_conn();
        assert!(!column_exists(&conn, "example", "missing").unwrap());
    }

    #[test]
    fn get_columns() {
        let conn = test_conn();
        let cols = get_column_names(&conn, "example").unwrap();
        assert_eq!(cols, vec!["id", "name", "age"]);
    }
}

//! convergio-db — Database pool, migration runner, schema registry.
//!
//! Provides r2d2 pool, collects migrations from all extensions,
//! tracks applied versions in `_schema_registry`.

pub mod core_tables;
pub mod ext;
pub mod helpers;
pub mod migration;
pub mod pool;
pub mod routes;

pub use ext::DbExtension;

//! Migration runner — collects migrations from extensions, applies in order.
//!
//! Each extension declares its migrations via Extension::migrations().
//! The runner tracks applied versions in `_schema_registry`.

use convergio_types::extension::Migration;
use rusqlite::Connection;

/// Ensures the schema registry table exists.
pub fn ensure_registry(conn: &Connection) -> rusqlite::Result<()> {
    conn.execute_batch(
        "CREATE TABLE IF NOT EXISTS _schema_registry (
            module TEXT PRIMARY KEY,
            version INTEGER NOT NULL,
            applied_at TEXT NOT NULL DEFAULT (datetime('now'))
        )",
    )
}

/// Returns the current version for a module, or 0 if not yet applied.
pub fn current_version(conn: &Connection, module: &str) -> rusqlite::Result<u32> {
    let mut stmt = conn.prepare("SELECT version FROM _schema_registry WHERE module = ?1")?;
    let version = stmt
        .query_row([module], |row| row.get::<_, u32>(0))
        .unwrap_or(0);
    Ok(version)
}

/// Apply pending migrations for a module.
/// Migrations must be sorted by version (ascending).
/// Returns the number of migrations applied.
///
/// Each statement is executed individually so that ALTER TABLE ADD COLUMN
/// errors caused by duplicate columns are silently skipped. This makes
/// migrations idempotent even when a previous run crashed mid-way and left
/// the schema in a half-applied state.
pub fn apply_migrations(
    conn: &Connection,
    module: &str,
    migrations: &[Migration],
) -> rusqlite::Result<usize> {
    ensure_registry(conn)?;
    let current = current_version(conn, module)?;
    let mut applied = 0;

    for m in migrations {
        if m.version <= current {
            continue;
        }
        tracing::info!(
            module,
            version = m.version,
            desc = m.description,
            "applying migration"
        );
        apply_sql_idempotent(conn, m.up)?;
        conn.execute(
            "INSERT OR REPLACE INTO _schema_registry (module, version) VALUES (?1, ?2)",
            rusqlite::params![module, m.version],
        )?;
        applied += 1;
    }
    Ok(applied)
}

/// Execute migration SQL, tolerating "duplicate column name" errors.
///
/// Strategy: try the whole batch first (fast path). If it fails with a
/// duplicate-column error, fall back to statement-by-statement execution
/// so only the offending ALTER TABLE is skipped while the rest succeeds.
///
/// The statement splitter is trigger-aware: semicolons inside
/// BEGIN...END blocks are not treated as statement boundaries.
fn apply_sql_idempotent(conn: &Connection, sql: &str) -> rusqlite::Result<()> {
    // Fast path — works for all migrations without duplicate columns.
    match conn.execute_batch(sql) {
        Ok(()) => return Ok(()),
        Err(e) if is_duplicate_column_error(&e) => {
            // Fall through to statement-by-statement retry.
        }
        Err(e) => return Err(e),
    }

    for stmt in split_statements(sql) {
        let trimmed = stmt.trim();
        if trimmed.is_empty() {
            continue;
        }
        match conn.execute_batch(trimmed) {
            Ok(()) => {}
            Err(e) if is_duplicate_column_error(&e) => {
                tracing::debug!("skipping already-applied: {trimmed}");
            }
            Err(e) => return Err(e),
        }
    }
    Ok(())
}

/// Split SQL into top-level statements on `;`, but keep semicolons
/// inside `BEGIN ... END` blocks intact (for triggers / compound stmts).
fn split_statements(sql: &str) -> Vec<&str> {
    let mut stmts = Vec::new();
    let mut start = 0;
    let mut depth = 0u32;
    let upper = sql.to_ascii_uppercase();
    let bytes = upper.as_bytes();
    let len = bytes.len();
    let mut i = 0;

    while i < len {
        if i + 5 <= len && &bytes[i..i + 5] == b"BEGIN" && is_word_boundary(bytes, i, 5, len) {
            depth += 1;
            i += 5;
        } else if i + 3 <= len && &bytes[i..i + 3] == b"END" && is_word_boundary(bytes, i, 3, len) {
            depth = depth.saturating_sub(1);
            i += 3;
        } else if bytes[i] == b';' && depth == 0 {
            stmts.push(&sql[start..i]);
            start = i + 1;
            i += 1;
        } else {
            i += 1;
        }
    }
    if start < len {
        stmts.push(&sql[start..]);
    }
    stmts
}

/// Returns true if position `pos..pos+word_len` sits on word boundaries.
fn is_word_boundary(bytes: &[u8], pos: usize, word_len: usize, len: usize) -> bool {
    let before_ok = pos == 0 || !bytes[pos - 1].is_ascii_alphanumeric();
    let after = pos + word_len;
    let after_ok = after >= len || !bytes[after].is_ascii_alphanumeric();
    before_ok && after_ok
}

/// Returns true if the error is a "duplicate column name" from ALTER TABLE.
fn is_duplicate_column_error(e: &rusqlite::Error) -> bool {
    e.to_string().contains("duplicate column name")
}

#[cfg(test)]
mod tests {
    use super::*;

    fn test_conn() -> Connection {
        let conn = Connection::open_in_memory().unwrap();
        conn.execute_batch("PRAGMA journal_mode=WAL;").unwrap();
        conn
    }

    #[test]
    fn registry_created_on_first_run() {
        let conn = test_conn();
        ensure_registry(&conn).unwrap();
        let exists: bool = conn
            .query_row(
                "SELECT COUNT(*) > 0 FROM sqlite_master WHERE name = '_schema_registry'",
                [],
                |r| r.get(0),
            )
            .unwrap();
        assert!(exists);
    }

    #[test]
    fn applies_migrations_in_order() {
        let conn = test_conn();
        let migrations = vec![
            Migration {
                version: 1,
                description: "create users",
                up: "CREATE TABLE users (id INTEGER PRIMARY KEY, name TEXT)",
            },
            Migration {
                version: 2,
                description: "add email",
                up: "ALTER TABLE users ADD COLUMN email TEXT",
            },
        ];
        let applied = apply_migrations(&conn, "test-mod", &migrations).unwrap();
        assert_eq!(applied, 2);
        assert_eq!(current_version(&conn, "test-mod").unwrap(), 2);
    }

    #[test]
    fn skips_already_applied() {
        let conn = test_conn();
        let migrations = vec![Migration {
            version: 1,
            description: "create table",
            up: "CREATE TABLE t1 (id INTEGER PRIMARY KEY)",
        }];
        apply_migrations(&conn, "mod-a", &migrations).unwrap();
        let applied = apply_migrations(&conn, "mod-a", &migrations).unwrap();
        assert_eq!(applied, 0);
    }

    #[test]
    fn duplicate_column_is_idempotent() {
        let conn = test_conn();
        // Simulate a partially-applied migration: column exists but version
        // was never recorded (crash between execute_batch and registry write).
        conn.execute_batch("CREATE TABLE t2 (id INTEGER PRIMARY KEY)")
            .unwrap();
        conn.execute_batch("ALTER TABLE t2 ADD COLUMN extra TEXT")
            .unwrap();
        // Now run a migration that tries to add the same column.
        let migrations = vec![Migration {
            version: 1,
            description: "add extra col",
            up: "ALTER TABLE t2 ADD COLUMN extra TEXT",
        }];
        let applied = apply_migrations(&conn, "mod-dup", &migrations).unwrap();
        assert_eq!(applied, 1);
        assert_eq!(current_version(&conn, "mod-dup").unwrap(), 1);
    }
}

//! SQLite connection pool with r2d2 and optimal PRAGMAs.

use r2d2::Pool;
use r2d2_sqlite::SqliteConnectionManager;
use std::path::Path;

/// Type alias for the connection pool.
pub type ConnPool = Pool<SqliteConnectionManager>;

/// Type alias for a pooled connection.
pub type PooledConn = r2d2::PooledConnection<SqliteConnectionManager>;

/// Standard PRAGMAs applied to every connection.
const PRAGMAS: &str = "\
    PRAGMA journal_mode=WAL;\
    PRAGMA synchronous=FULL;\
    PRAGMA busy_timeout=5000;\
    PRAGMA cache_size=-8000;\
    PRAGMA mmap_size=67108864;\
    PRAGMA temp_store=MEMORY;\
";

/// Create a connection pool for the given database path.
pub fn create_pool(db_path: &Path) -> Result<ConnPool, r2d2::Error> {
    let manager = SqliteConnectionManager::file(db_path).with_init(|conn| {
        conn.execute_batch(PRAGMAS)
            .map_err(|e| rusqlite::Error::ToSqlConversionFailure(Box::new(e)))
    });
    Pool::builder().max_size(8).min_idle(Some(2)).build(manager)
}

/// Create an in-memory pool (for testing).
pub fn create_memory_pool() -> Result<ConnPool, r2d2::Error> {
    let manager = SqliteConnectionManager::memory().with_init(|conn| {
        conn.execute_batch("PRAGMA journal_mode=WAL; PRAGMA busy_timeout=5000;")
            .map_err(|e| rusqlite::Error::ToSqlConversionFailure(Box::new(e)))
    });
    Pool::builder().max_size(1).build(manager)
}

#[cfg(test)]
mod tests {
    use super::*;

    #[test]
    fn memory_pool_works() {
        let pool = create_memory_pool().expect("pool creation");
        let conn = pool.get().expect("get connection");
        conn.execute_batch("CREATE TABLE test_pool (id INTEGER PRIMARY KEY)")
            .expect("create table");
    }
}

